select.isEqual:
SELECT DOCID , 'NULL' PROCESSORID , 'NULL' RECEIVEDDEPTID FROM TBL_APRLINEINFO WHERE DOCID = #v_PDOCID# AND ( APRMEMBERID = #v_PAPRUSERID#
OR APRMEMBERID IN (SELECT OWNERID FROM TBL_PS_SHAREAPPROVAL WHERE TENANTID = #v_TENANTID# AND SHAREUSERID = #v_PAPRUSERID#)
) AND ( APRSTATE = '002' OR APRSTATE = '005' OR APRSTATE = '000' ) AND TENANT_ID = #v_TENANTID# AND COMPANYID IN ( SELECT EXTENSIONATTRIBUTE2 FROM TBL_DEPTMASTER INNER JOIN TBL_ADDJOBMASTER ON (TBL_ADDJOBMASTER.TENANT_ID = TBL_DEPTMASTER.TENANT_ID AND TBL_DEPTMASTER.CN = TBL_ADDJOBMASTER.DEPTID) WHERE TBL_ADDJOBMASTER.TENANT_ID = #v_TENANTID# AND TBL_ADDJOBMASTER.CN = #v_PAPRUSERID# UNION ALL SELECT PHYSICALDELIVERYOFFICENAME FROM TBL_USERMASTER WHERE CN = #v_PAPRUSERID# AND TENANT_ID = #v_TENANTID# )

