select.isEqual:
SELECT COUNT(TBL_APRRECEIPTPROCESSINFO.DOCID) FROM TBL_APRRECEIPTPROCESSINFO INNER JOIN TBL_APRDOCINFO ON TBL_APRRECEIPTPROCESSINFO.DOCID = TBL_APRDOCINFO.DOCID AND TBL_APRRECEIPTPROCESSINFO.TENANT_ID = TBL_APRDOCINFO.TENANT_ID AND TBL_APRRECEIPTPROCESSINFO.COMPANYID = TBL_APRDOCINFO.COMPANYID INNER JOIN TBL_EXPAPRDOCINFO ON TBL_EXPAPRDOCINFO.DOCID = TBL_APRDOCINFO.DOCID AND TBL_EXPAPRDOCINFO.TENANT_ID = TBL_APRDOCINFO.TENANT_ID AND TBL_EXPAPRDOCINFO.COMPANYID = TBL_APRDOCINFO.COMPANYID WHERE TBL_APRRECEIPTPROCESSINFO.PROCESSYN <> ''Y'' AND (((TBL_APRRECEIPTPROCESSINFO.PROCESSORID = #v_USERID# AND TBL_APRRECEIPTPROCESSINFO.RECEIVEDDEPTID = #v_DEPTID#) AND (TBL_APRRECEIPTPROCESSINFO.APRSTATE = '012' OR TBL_APRRECEIPTPROCESSINFO.APRSTATE = '015' OR TBL_APRRECEIPTPROCESSINFO.APRSTATE = '011')) AND TBL_APRRECEIPTPROCESSINFO.TENANT_ID = #v_TENANTID# AND TBL_APRRECEIPTPROCESSINFO.COMPANYID IN ( SELECT EXTENSIONATTRIBUTE2 FROM TBL_DEPTMASTER INNER JOIN TBL_ADDJOBMASTER ON (TBL_ADDJOBMASTER.TENANT_ID = TBL_DEPTMASTER.TENANT_ID AND TBL_DEPTMASTER.CN = TBL_ADDJOBMASTER.DEPTID) WHERE TBL_ADDJOBMASTER.TENANT_ID = #v_TENANTID# AND TBL_ADDJOBMASTER.CN = #v_USERID# UNION ALL SELECT PHYSICALDELIVERYOFFICENAME FROM TBL_USERMASTER WHERE CN = #v_USERID# AND TENANT_ID = #v_TENANTID# )
OR (TBL_APRRECEIPTPROCESSINFO.RECEIVEDDEPTID IN (#v_DEPTIDS#) AND TBL_APRRECEIPTPROCESSINFO.APRSTATE IN ('011', '014', '015') AND PROCESSORID IS NULL )
)

