INSERT INTO TBL_APRRECEIPTPROCESSINFO ( ReceiveSN, DocID, SentDeptID, SentDeptName, SentDeptName2, ReceivedDeptID, ReceivedDeptName, ReceivedDeptName2, DocState, AprState, ProcessDate, ProcessYN, ProcessDocID, ProcessorID, ProcessorName, ProcessorName2, ProcessorJobTitle, ProcessorJobTitle2, ParentsDocID, TENANT_ID, COMPANYID) (select #v_PSN# , DocID, ReceivedDeptID, ReceivedDeptName, ReceivedDeptName2, #v_WRITERDEPTID#, #v_WRITERDEPTNAME#, #v_WRITERDEPTNAME2#, DocState, #v_APRSTATE#, TO_DATE(#v_SYSDATE#,'YYYY-MM-DD HH24:MI:SS'), 'N', '', '', '', '', '', '', DocID, TENANT_ID, COMPANYID from (SELECT * FROM TBL_APRRECEIPTPROCESSINFO WHERE DocID = #v_DOCID# AND ReceiveSN = #v_RECEIVESN# AND TENANT_ID = #v_TENANTID# AND companyid = #companyID#
order by ProcessDate desc ) where ROWNUM <= 1 )
) )

